import{_ as a,o,c as i,ag as c}from"./chunks/framework.DTiDeF2Q.js";const w=JSON.parse('{"title":"Aliasy Archiwow | Dotfiles (PL)","titleTemplate":":title","description":"Skrocone polecenia archiwizacji. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","frontmatter":{"title":"Aliasy Archiwow | Dotfiles","description":"Skrocone polecenia archiwizacji. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","lang":"pl-PL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasy Archiwow | Dotfiles preview","canonical":"/pl/aliases/archives/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasy Archiwow","pageType":"docs","schemaType":"WebPage","permalink":"/pl/aliases/archives/"},"headers":[],"relativePath":"pl/aliases/archives/index.md","filePath":"pl/aliases/archives/index.md","lastUpdated":1773010926000}'),r={name:"pl/aliases/archives/index.md"};function l(t,e,d,s,n,p){return o(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="aliasy-archiwow" tabindex="-1">Aliasy Archiwow <a class="header-anchor" href="#aliasy-archiwow" aria-label="Permalink to &quot;Aliasy Archiwow&quot;">​</a></h1><p>Skrocone nazwy polecen archiwizacji.</p><p>Ta strona przedstawia jedna grupe aliasow i jej typowe skroty polecen. Przeczytaj ja najpierw, aby zrozumiec konwencje nazewnictwa, oczekiwane dane wejsciowe i bezpieczne wzorce wykonywania. Nastepnie otworz dodatek referencyjny, aby zobaczyc pelny spis polecen i dokladna skladnie. Te aliasy redukuja powtarzalne wpisywanie i zapewniaja spojne zachowanie przeplywy pracy na macOS, Linux i WSL.</p><h2 id="kiedy-uzywac" tabindex="-1">Kiedy uzywac <a class="header-anchor" href="#kiedy-uzywac" aria-label="Permalink to &quot;Kiedy uzywac&quot;">​</a></h2><p>Uzyj tej strony przed codziennym uzywaniem powloki, gdy potrzebujesz przewidywalnych wzorcow polecen.</p><h2 id="co-zawiera" tabindex="-1">Co zawiera <a class="header-anchor" href="#co-zawiera" aria-label="Permalink to &quot;Co zawiera&quot;">​</a></h2><ul><li>Aliasy: 40</li><li>Funkcje pomocnicze: 3</li><li>Pliki zrodlowe: 1</li></ul><h2 id="szybkie-przyklady" tabindex="-1">Szybkie przyklady <a class="header-anchor" href="#szybkie-przyklady" aria-label="Permalink to &quot;Szybkie przyklady&quot;">​</a></h2><ul><li><code>ac</code> -&gt; <code>&#39;compress&#39; # Ogolna kompresja (Archive Create)</code></li><li><code>acl</code> -&gt; <code>&#39;compress_large&#39; # Starsza kompresja duzych plikow</code></li><li><code>bak</code> -&gt; <code>&#39;backup&#39; # Szybka kopia zapasowa</code></li><li><code>c7z</code> -&gt; <code>&#39;7z a&#39; # Utworz archiwum 7z</code></li><li><code>cbz</code> -&gt; <code>&#39;bzip2 -zk&#39; # Kompresuj za pomoca bzip2</code></li><li><code>cgz</code> -&gt; <code>&#39;gzip -cv&#39; # Kompresuj za pomoca gzip</code></li><li><code>clz4</code> -&gt; <code>&#39;lz4 -zc&#39; # Kompresuj za pomoca lz4</code></li><li><code>crar</code> -&gt; <code>&#39;rar a&#39; # Utworz archiwum rar</code></li><li><code>ctar</code> -&gt; <code>&#39;tar -cvf&#39; # Utworz archiwum tar</code></li><li><code>ctbz</code> -&gt; <code>&#39;tar -jcvf&#39; # Utworz archiwum tar.bz2</code></li><li><code>ctgz</code> -&gt; <code>&#39;tar -zcvf&#39; # Utworz archiwum tar.gz</code></li><li><code>ctxz</code> -&gt; <code>&#39;tar -Jcvf&#39; # Utworz archiwum tar.xz</code></li></ul><h2 id="nastepny-krok" tabindex="-1">Nastepny krok <a class="header-anchor" href="#nastepny-krok" aria-label="Permalink to &quot;Nastepny krok&quot;">​</a></h2><p>Otworz pelna liste:</p>',11)])])}const y=a(r,[["render",l]]);export{w as __pageData,y as default};
